1	// game-of-life.ts
2	export type Cell = [number, number];
3	
4	const isSameCell = ([x, y]: Cell, [ox, oy]: Cell): boolean =>
5	  x === ox && y === oy;
6	
7	const offsets = [-1, 0, 1];
8	
9	const neighborsOf = (cell: Cell): Cell[] =>
10	  offsets
11	    .flatMap((dx) => offsets.map((dy): Cell => [cell[0] + dx, cell[1] + dy]))
12	    .filter((candidate) => !isSameCell(candidate, cell));
13	
14	const contains = (cells: Cell[], cell: Cell): boolean =>
15	  cells.some((other) => isSameCell(other, cell));
16	
17	const unique = (cells: Cell[]): Cell[] =>
18	  cells.filter((cell, index) => !contains(cells.slice(0, index), cell));
19	
20	const countLiveNeighbors = (cell: Cell, liveCells: Cell[]): number =>
21	  neighborsOf(cell).filter((neighbor) => contains(liveCells, neighbor)).length;
22	
23	const survives = (liveNeighborCount: number): boolean =>
24	  liveNeighborCount === 2 || liveNeighborCount === 3;
25	
26	const isBorn = (liveNeighborCount: number): boolean =>
27	  liveNeighborCount === 3;
28	
29	export const nextGeneration = (liveCells: Cell[]): Cell[] => {
30	  const survivors = liveCells.filter((cell) =>
31	    survives(countLiveNeighbors(cell, liveCells)),
32	  );
33	  const born = unique(liveCells.flatMap(neighborsOf))
34	    .filter((cell) => !contains(liveCells, cell))
35	    .filter((cell) => isBorn(countLiveNeighbors(cell, liveCells)));
36	  return [...survivors, ...born];
37	};
