it("should keep a block (still life) unchanged", () => {
  // Gen 0:        Gen 1:
  //  ##            ##    ← every cell has exactly 3 live
  //  ##            ##      neighbors, no dead cell has 3
  expect(
    sorted(
      nextGeneration([
        [0, 0],
        [1, 0],
        [0, 1],
        [1, 1],
      ]),
    ),
  ).toEqual(
    sorted([
      [0, 0],
      [1, 0],
      [0, 1],
      [1, 1],
    ]),
  );
});
